    {
      "keystrokes": "find / -name 'libblas*' -o -name 'libRblas*' -o -name 'libgfortran*' 2>/dev/null\n",
      "duration": 10.0
    },
    {
      "keystrokes": "dpkg -l | grep -i 'blas\\|lapack\\|gfortran\\|linear' 2>&1 | head -20\n",
      "duration": 5.0
    },
    {
      "keystrokes": "locate libblas 2>/dev/null || find /usr -name '*blas*' 2>/dev/null | head -20\n",
      "duration": 10.0
    }
  ],
